var e=[{id:`L2_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_X`,text:{KOREA:`……어라?`,JPN:`……あれ？`,ENG:`...Huh?`,TWN:`……嗯？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_X`,text:{KOREA:`보라 누나! 저 기사 몬스터…… 왠지 다른 몬스터랑 다른 것 같은데요?`,JPN:`シホさん！　あの騎士のモンスター……なんだか他のモンスターと違いますよ？`,ENG:`Bora! That knight monster... It looks different from the others!`,TWN:`寶拉姊姊！那個騎士怪物……好像和其他怪物不太一樣欸？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_X`,text:{KOREA:`색깔도 왠지 어두운 것 같고…… 그리고 다른 몬스터랑 달리 엄청 센 거 같아요!`,JPN:`色もなんか暗いし……それに、他のモンスターと違ってめちゃくちゃ強いみたいです！`,ENG:`It’s darker in color... and is really hard to beat!`,TWN:`顏色暗暗的……而且好像特別強！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`BORA_GAMECIRCLE_NULL_NULL`,text:{KOREA:`조회해 볼게……. 데이터 로그.`,JPN:`検索してみる……データログ。`,ENG:`The data log… I’ll check.`,TWN:`我查查……數據紀錄。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_SERIOUS2`},C:null,R:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`BORA_GAMECIRCLE_NULL_NULL`,text:{KOREA:`맞는 것 같아…… 아마도.`,JPN:`合ってると思う……たぶん。`,ENG:`That’s the one... I think.`,TWN:`好像沒錯……應該。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_SERIOUS2`},C:null,R:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}},sfx:`TYPING_LOOP`},{id:`L9_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_X`,text:{KOREA:`그럼, 버그를 유발하는 몬스터를 찾았으니까 이제 끝난 거예요?`,JPN:`じゃあ、バグを誘発するモンスターを見つけ出したから、もう大丈夫ですか？`,ENG:`Then are we done? We found the source of the problem.`,TWN:`既然已經找到發生Bug的怪物，那應該OK了吧？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},C:null,R:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`BORA_GAMECIRCLE_NULL_NULL`,text:{KOREA:`확인해야 해……. 정말로 발생하는지……. 버그.`,JPN:`確認しなきゃ……本当に発生するのか……バグ。`,ENG:`We should check... if the bug's... still there.`,TWN:`現在……要重現……Bug。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},C:null,R:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L11_1`,type:`dialog`,speaker:`BORA_GAMECIRCLE_NULL_NULL`,text:{KOREA:`쓰러트리는 거야…… 억지로.`,JPN:`倒すの……無理やり。`,ENG:`We take it down... by force.`,TWN:`必須……倒下。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},C:null,R:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L12_1`,type:`dialog`,speaker:`BORA_GAMECIRCLE_NULL_NULL`,text:{KOREA:`쓰러지지 않는 검은 기사를……!`,JPN:`倒れない黒い騎士を……！`,ENG:`Beat the unbeatable...!`,TWN:`原本不該倒下的騎士……！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`BOX_NPC_GAMECIRCLE_X`,face:`UNIT_IDLE`},C:null,R:{char_id:`BORA_GAMECIRCLE_NULL_NULL`,face:`UNIT_SERIOUS`}}}}];export{e as default};